const path = require('path');
const express = require('express');
const session = require('express-session');
const cookieParser = require('cookie-parser');
const expressLayouts = require('express-ejs-layouts');
const swaggerUi = require('swagger-ui-express');
const swaggerJsdoc = require('swagger-jsdoc');
const env = require('./config/env');
const { attachAuditContext, requireRole } = require('./middleware/auth');
const { csrfTokenMiddleware, csrfProtection } = require('./middleware/csrf');
const userService = require('./services/userService');

const accountPages = require('./routes/pages/account');
const adminPages = require('./routes/pages/admin');
const psicologoPages = require('./routes/pages/psicologo');
const pacientePages = require('./routes/pages/paciente');
const homePages = require('./routes/pages/home');

const userApi = require('./routes/api/user');
const calendarApi = require('./routes/api/calendar');
const psicologoAgendaApi = require('./routes/api/psicologoAgenda');
const pacienteAgendaApi = require('./routes/api/pacienteAgenda');

function createApp() {
  const app = express();

  app.set('trust proxy', 1);
  app.set('view engine', 'ejs');
  app.set('views', path.join(__dirname, '..', 'views'));
  app.use(expressLayouts);
  app.set('layout extractScripts', true);
  app.set('layout extractStyles', true);

  app.use(express.json());
  app.use(express.urlencoded({ extended: true }));
  app.use(cookieParser());
  app.use(express.static(path.join(__dirname, '..', 'public')));

  app.use(session({
    secret: env.sessionSecret,
    resave: false,
    saveUninitialized: false,
    rolling: true,
    cookie: {
      maxAge: 30 * 60 * 1000,
      httpOnly: true,
      secure: env.cookieSecure,
      sameSite: 'lax',
    },
  }));

  app.use(attachAuditContext);
  app.use(csrfProtection);
  app.use(csrfTokenMiddleware);

  app.use((req, res, next) => {
    res.locals.userName = req.session?.userName || '';
    res.locals.csrfToken = res.locals.csrfToken || '';
    next();
  });

  app.get('/login', (req, res) => res.redirect('/account/login'));

  if (env.isDev) {
    const swaggerSpec = swaggerJsdoc({
      definition: {
        openapi: '3.0.0',
        info: {
          title: 'ScheduleClin API',
          version: 'v1',
          description: 'API para gestão de agendamentos, usuários e perfis',
        },
      },
      apis: [path.join(__dirname, 'routes', 'api', '*.js')],
    });
    app.use('/api-docs', swaggerUi.serve, swaggerUi.setup(swaggerSpec));
  }

  app.use('/', homePages);
  app.use('/account', accountPages);
  app.use('/admin', adminPages);
  app.use('/psicologo', psicologoPages);
  app.use('/paciente', pacientePages);

  app.get('/get-users', requireRole('Gestor'), async (req, res) => {
    try {
      res.json(await userService.getUsers());
    } catch (err) {
      console.error(err);
      res.status(500).json({ message: 'Erro interno.' });
    }
  });

  app.use('/api/User', userApi);
  app.use('/api/Calendar', calendarApi);
  app.use('/api/PsicologoAgenda', psicologoAgendaApi);
  app.use('/api/PacienteAgenda', pacienteAgendaApi);

  app.use((err, req, res, next) => {
    const dbUnreachable = err?.code === 'P1001'
      || err?.code === 'P1017'
      || err?.name === 'PrismaClientInitializationError'
      || (typeof err?.message === 'string' && err.message.includes("Can't reach database server"));

    if (dbUnreachable && !req.path.startsWith('/api')) {
      return res.status(503).send(
        'Banco de dados indisponível. Verifique se o MySQL/MariaDB está rodando (XAMPP) e o DATABASE_URL no .env.',
      );
    }

    if (err.code === 'EBADCSRFTOKEN') {
      if (req.path.startsWith('/api') || req.originalUrl.startsWith('/api')) {
        return res.status(403).json({ message: 'Token CSRF inválido.' });
      }
      res.clearCookie('_csrf');
      return res.status(403).send(
        'Sessão expirada ou token inválido. Atualize a página (F5) e tente novamente.',
      );
    }
    console.error(err);
    res.status(500).send('Erro interno.');
  });

  return app;
}

module.exports = { createApp };

const { randomUUID } = require('crypto');
const { getPrisma } = require('../utils/prisma');
const { ProfileIds, Perfis } = require('../utils/perfis');
const {
  hashPassword,
  normalize,
  newSecurityStamp,
  newConcurrencyStamp,
} = require('../utils/password');

async function seedProfiles(prisma) {
  const perfis = [
    { profileId: ProfileIds.Gestor, name: Perfis.Gestor, description: 'Administrador do sistema' },
    { profileId: ProfileIds.Psicologo, name: Perfis.Psicologo, description: 'Funcionário — psicólogo(a)' },
    { profileId: ProfileIds.Paciente, name: Perfis.Paciente, description: 'Paciente da clínica' },
  ];

  for (const perfil of perfis) {
    const exists = await prisma.profile.findUnique({ where: { profileId: perfil.profileId } });
    if (!exists) await prisma.profile.create({ data: perfil });
  }
}

async function seedRoles(prisma) {
  for (const papel of Perfis.Todos) {
    const exists = await prisma.role.findFirst({ where: { normalizedName: normalize(papel) } });
    if (!exists) {
      await prisma.role.create({
        data: {
          id: randomUUID(),
          name: papel,
          normalizedName: normalize(papel),
          concurrencyStamp: newConcurrencyStamp(),
        },
      });
    }
  }
}

async function seedGestor(prisma) {
  const emailGestor = 'gestor@scheduleclin.local';
  let gestor = await prisma.user.findFirst({ where: { normalizedEmail: normalize(emailGestor) } });

  const gestorRole = await prisma.role.findFirst({ where: { normalizedName: normalize(Perfis.Gestor) } });

  if (gestor) {
    if (!gestor.perfilId) {
      await prisma.user.update({ where: { id: gestor.id }, data: { perfilId: ProfileIds.Gestor } });
    }
    if (gestorRole) {
      const hasRole = await prisma.userRole.findUnique({
        where: { userId_roleId: { userId: gestor.id, roleId: gestorRole.id } },
      });
      if (!hasRole) await prisma.userRole.create({ data: { userId: gestor.id, roleId: gestorRole.id } });
    }
    return;
  }

  gestor = await prisma.user.create({
    data: {
      id: randomUUID(),
      userName: emailGestor,
      normalizedUserName: normalize(emailGestor),
      email: emailGestor,
      normalizedEmail: normalize(emailGestor),
      emailConfirmed: true,
      passwordHash: hashPassword('Gestor@123'),
      securityStamp: newSecurityStamp(),
      concurrencyStamp: newConcurrencyStamp(),
      perfilId: ProfileIds.Gestor,
      dataNascimento: new Date('1990-01-01'),
      mustChangePassword: true,
      active: true,
    },
  });

  if (gestorRole) {
    await prisma.userRole.create({ data: { userId: gestor.id, roleId: gestorRole.id } });
  }
}

async function syncExistingUsers(prisma) {
  const users = await prisma.user.findMany({ include: { perfil: true } });
  const profiles = await prisma.profile.findMany();

  for (const user of users) {
    const userRoles = await prisma.userRole.findMany({
      where: { userId: user.id },
      include: { role: true },
    });
    const roles = userRoles.map((ur) => ur.role?.name).filter(Boolean);

    if (roles.length > 0 && !user.perfilId) {
      const profile = profiles.find((p) => p.name === roles[0]);
      if (profile) {
        await prisma.user.update({ where: { id: user.id }, data: { perfilId: profile.profileId } });
      }
    } else if (user.perfilId && roles.length === 0 && user.perfil?.name) {
      const role = await prisma.role.findFirst({ where: { normalizedName: normalize(user.perfil.name) } });
      if (role) await prisma.userRole.create({ data: { userId: user.id, roleId: role.id } });
    }
  }
}

async function seed() {
  const prisma = getPrisma();
  const { runWithAuditContext } = require('../middleware/audit');
  await runWithAuditContext({ skipAudit: true }, async () => {
    await seedProfiles(prisma);
    await seedRoles(prisma);
    await seedGestor(prisma);
    await syncExistingUsers(prisma);
  });
  console.log('Seed concluído.');
}

module.exports = { seed };

const { AsyncLocalStorage } = require('async_hooks');

const auditContext = new AsyncLocalStorage();

const RUIDO = new Set([
  'passwordHash', 'securityStamp', 'concurrencyStamp',
  'accessFailedCount', 'lockoutEnd', 'lockoutEnabled',
  'normalizedUserName', 'normalizedEmail',
]);

function runWithAuditContext(context, fn) {
  return auditContext.run(context, fn);
}

function getAuditContext() {
  return auditContext.getStore();
}

function montarDetalhes(before, after) {
  if (!before || !after) return null;
  const parts = [];
  for (const key of Object.keys(after)) {
    if (RUIDO.has(key)) continue;
    if (before[key] instanceof Date && after[key] instanceof Date) {
      if (before[key].getTime() !== after[key].getTime()) parts.push(`${key}=${after[key].toISOString()}`);
    } else if (String(before[key]) !== String(after[key])) {
      parts.push(`${key}=${after[key]}`);
    }
  }
  return parts.length > 0 ? parts.join('; ') : null;
}

function createAuditExtension(baseClient) {
  return {
    name: 'audit',
    query: {
      async $allOperations({ model, operation, args, query }) {
        const auditable = model === 'User' || model === 'Calendar';
        const ctx = getAuditContext();

        if (!auditable || !ctx || operation === 'findMany' || operation === 'findFirst' || operation === 'findUnique' || operation === 'count') {
          return query(args);
        }

        const modelClient = { User: 'user', Calendar: 'calendar' }[model];
        if (!modelClient) return query(args);

        let before = null;
        if (operation === 'update' || operation === 'delete') {
          const idField = model === 'User' ? 'id' : 'calendarID';
          const id = args.where?.[idField];
          if (id) {
            before = await baseClient[modelClient].findUnique({ where: { [idField]: id } });
          }
        }

        const result = await query(args);

        if (ctx.skipAudit) return result;

        let action;
        let entityId;
        let details = null;

        if (operation === 'create') {
          action = `Added ${model}`;
          entityId = model === 'User' ? result.id : result.calendarID;
        } else if (operation === 'update') {
          details = montarDetalhes(before, result);
          if (!details) return result;
          action = `Modified ${model}`;
          entityId = model === 'User' ? result.id : result.calendarID;
        } else if (operation === 'delete') {
          action = `Deleted ${model}`;
          entityId = model === 'User' ? before?.id : before?.calendarID;
        } else {
          return result;
        }

        await baseClient.auditLog.create({
          data: {
            userId: ctx.userId || null,
            userName: ctx.userName || null,
            action,
            entity: model,
            entityId: entityId ? String(entityId) : null,
            details,
            ipAddress: ctx.ipAddress || null,
          },
        });

        return result;
      },
    },
  };
}

async function registrarAudit(prisma, { action, userId, userName, details, ipAddress, entity, entityId }) {
  await prisma.auditLog.create({
    data: {
      action,
      userId: userId || null,
      userName: userName || null,
      details: details || null,
      ipAddress: ipAddress || null,
      entity: entity || null,
      entityId: entityId || null,
    },
  });
}

module.exports = {
  runWithAuditContext,
  getAuditContext,
  createAuditExtension,
  registrarAudit,
};

const { runWithAuditContext } = require('./audit');

function attachAuditContext(req, res, next) {
  const ctx = {
    userId: req.session?.userId || null,
    userName: req.session?.userName || null,
    ipAddress: req.ip || req.connection?.remoteAddress || null,
    skipAudit: false,
  };
  runWithAuditContext(ctx, () => next());
}

function requireAuth(req, res, next) {
  if (req.session?.userId) return next();

  if (req.path.startsWith('/api') || req.originalUrl.startsWith('/api') || req.originalUrl.startsWith('/get-users')) {
    return res.status(401).json({ message: 'Não autenticado.' });
  }
  return res.redirect('/account/login');
}

function requireRole(...roles) {
  return (req, res, next) => {
    if (!req.session?.userId) {
      if (req.path.startsWith('/api') || req.originalUrl.startsWith('/api')) {
        return res.status(401).json({ message: 'Não autenticado.' });
      }
      return res.redirect('/account/login');
    }

    const userRoles = req.session.roles || [];
    if (roles.some((r) => userRoles.includes(r))) return next();

    if (req.path.startsWith('/api') || req.originalUrl.startsWith('/api')) {
      return res.status(403).json({ message: 'Acesso negado.' });
    }
    return res.redirect('/account/access-denied');
  };
}

function redirectIfAuthenticated(req, res, next) {
  if (req.session?.userId && !req.session?.mustChangePassword) {
    return res.redirect(getHomeByRoles(req.session.roles || []));
  }
  next();
}

function getHomeByRoles(roles) {
  if (roles.includes('Gestor')) return '/admin/users';
  if (roles.includes('Psicologo')) return '/psicologo/agenda';
  if (roles.includes('Paciente')) return '/paciente/consultas';
  return '/';
}

module.exports = {
  attachAuditContext,
  requireAuth,
  requireRole,
  redirectIfAuthenticated,
  getHomeByRoles,
};

